// Calculate overall backlink quality score
const items = $input.all();
const summary = items.find(i => i.json.total_backlinks !== undefined)?.json || {};
const daDistribution = items.filter(i => i.json.domain_authority !== undefined).map(i => i.json);

// Quality score components
const avgDA = summary.avg_domain_authority || 0;
const dofollowRatio = summary.total_backlinks > 0 ? (summary.dofollow_count / summary.total_backlinks) : 0;
const toxicRatio = summary.total_backlinks > 0 ? (summary.toxic_backlinks / summary.total_backlinks) : 0;
const diversityScore = Math.min(100, (summary.referring_domains / summary.total_backlinks) * 100);

// Calculate DA tiers
const highDA = daDistribution.filter(d => d.domain_authority >= 50).reduce((sum, d) => sum + d.count, 0);
const medDA = daDistribution.filter(d => d.domain_authority >= 20 && d.domain_authority < 50).reduce((sum, d) => sum + d.count, 0);
const lowDA = daDistribution.filter(d => d.domain_authority < 20).reduce((sum, d) => sum + d.count, 0);

// Overall quality score (0-100)
const qualityScore = Math.round(
  (avgDA * 0.3) +
  (dofollowRatio * 30) +
  (diversityScore * 0.2) +
  ((1 - toxicRatio) * 20)
);

return [{
  json: {
    quality_score: qualityScore,
    total_backlinks: summary.total_backlinks,
    referring_domains: summary.referring_domains,
    avg_domain_authority: Math.round(avgDA),
    dofollow_ratio: Math.round(dofollowRatio * 100),
    toxic_ratio: Math.round(toxicRatio * 100),
    diversity_score: Math.round(diversityScore),
    da_tiers: {
      high: highDA,
      medium: medDA,
      low: lowDA
    },
    new_last_30_days: summary.new_last_30_days
  }
}];

